                    return False
            elif isinstance(op, ast.NotEq):
                if not (results[-2] != results[-1]):
                    return False
            elif isinstance(op, ast.Lt):
                if not (results[-2] < results[-1]):
                    return False
            elif isinstance(op, ast.LtE):
                if not (results[-2] <= results[-1]):
                    return False
            elif isinstance(op, ast.Gt):
                if not (results[-2] > results[-1]):
                    return False
            elif isinstance(op, ast.GtE):
                if not (results[-2] >= results[-1]):
                    return False
            elif isinstance(op, ast.Is):
                if not (results[-2] is results[-1]):
                    return False
            elif isinstance(op, ast.IsNot):
                if not (results[-2] is not results[-1]):
                    return False
            elif isinstance(op, ast.In):
                if not (results[-2] in results[-1]):
                    return False
            elif isinstance(op, ast.NotIn):
                if not (results[-2] not in results[-1]):
                    return False
